import Image from 'next/image';

export interface AgentTemplate {
  id: string;
  slug: string;
  title: string;
  description: string;
  category: string;
  icon?: string;
  isFeatured: boolean;
  accentColor?: string;
}

interface TemplateCardProps {
  template: AgentTemplate;
  onClick: (slug: string) => void;
}

export default function TemplateCard({ template, onClick }: TemplateCardProps) {
  
  if (template.isFeatured) {
    return (
      <button 
        onClick={() => onClick(template.slug)}
        className={`relative w-full text-left overflow-hidden rounded-[20px] p-6 h-[170px] transition-transform hover:scale-[1.02] hover:shadow-md focus:outline-none focus:ring-2 focus:ring-blue-500/50 block group ${template.accentColor || 'bg-blue-50'}`}
        aria-label={`Featured template: ${template.title} - ${template.description}`}
      >
        <div className="relative z-10 max-w-[65%]">
          <h3 className="text-[17px] font-semibold text-blue-900 tracking-tight leading-[1.2] mb-1.5 group-hover:text-blue-700 transition-colors">
            {template.title}
          </h3>
          <p className="text-[13px] text-blue-800/70 leading-relaxed font-medium">
            {template.description}
          </p>
        </div>
        
        {/* Decorative Graphic Element Mock - Absolute mapped to the bottom right */}
        <div className="absolute right-0 bottom-0 pointer-events-none w-[140px] h-[120px] opacity-90 transition-transform group-hover:translate-x-1 group-hover:-translate-y-1">
           {/* Replace with the actual SVG/Image from design. Simple rect block representation for the mock */}
           <div className="absolute w-[180px] h-[200px] right-[-20px] bottom-[-40px] bg-white rounded-tl-xl border border-gray-200/50 shadow-sm flex items-start justify-center pt-4">
             <div className="w-[120px] h-3 bg-gray-100/80 rounded block border border-gray-100"></div>
           </div>
        </div>
      </button>
    );
  }

  // Standard Template Card
  return (
    <button 
      onClick={() => onClick(template.slug)}
      className="relative w-full text-left bg-white border border-gray-100 rounded-[20px] p-5 h-[170px] transition-all hover:border-gray-300 hover:shadow-sm focus:outline-none focus:ring-2 focus:ring-gray-300 group flex flex-col items-start justify-start"
      aria-label={`Template: ${template.title}`}
    >
      <div className="w-[34px] h-[34px] bg-blue-50/80 text-blue-500 rounded-xl flex items-center justify-center mb-3 shadow-sm border border-blue-100/50 group-hover:bg-blue-100 transition-colors">
        <span className="text-[18px]" aria-hidden="true">{template.icon || '💬'}</span>
      </div>
      
      <h3 className="text-[15px] font-semibold text-gray-900 tracking-tight leading-snug mb-1 group-hover:text-blue-600 transition-colors">
        {template.title}
      </h3>
      
      {template.description && (
        <p className="text-[13px] text-gray-400 font-medium leading-[1.4] mt-auto">
          {template.description}
        </p>
      )}
    </button>
  );
}
